module d_flip_flop (
    input clk,
    input reset_n,
    input enable,
    input d,
    output reg q);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or negedge reset_n or posedge dbg_halt) begin
    if (!reset_n)
        q <= 0;
    else if (enable)
        q <= d;
end

endmodule
